                const reversedIndex = inputText.length - 1 - i;
                const activeSpan = charAnimation.children[reversedIndex + 1];
                activeSpan.classList.add('active');

                // Animate character
                animationField.appendChild(charAnimation);
                setTimeout(() => {
                    activeSpan.classList.remove('active');
                }, 200);
            }
        });
